module.exports=[92690,66005,a=>{"use strict";a.s(["CardImage",()=>l],92690);var b=a.i(87924),c=a.i(72131),d=a.i(60768);a.s(["SUIT_LABELS",()=>h,"buildCardImagePath",()=>k,"getCardCategory",()=>j,"getTileLabel",()=>i],66005);let e=[{number:1,rank:"As",rankSlug:"as",roman:"I"},{number:2,rank:"Dos",rankSlug:"dos",roman:"II"},{number:3,rank:"Tres",rankSlug:"tres",roman:"III"},{number:4,rank:"Cuatro",rankSlug:"cuatro",roman:"IV"},{number:5,rank:"Cinco",rankSlug:"cinco",roman:"V"},{number:6,rank:"Seis",rankSlug:"seis",roman:"VI"},{number:7,rank:"Siete",rankSlug:"siete",roman:"VII"},{number:8,rank:"Ocho",rankSlug:"ocho",roman:"VIII"},{number:9,rank:"Nueve",rankSlug:"nueve",roman:"IX"},{number:10,rank:"Diez",rankSlug:"diez",roman:"X"},{number:11,rank:"Sota",rankSlug:"sota",roman:"XI"},{number:12,rank:"Caballero",rankSlug:"caballero",roman:"XII"},{number:13,rank:"Reina",rankSlug:"reina",roman:"XIII"},{number:14,rank:"Rey",rankSlug:"rey",roman:"XIV"}],f=[{suit:"bastos",label:"Bastos",meanings:[{keywords:["inspiración","impulso","comienzo creativo"],up:"El As de Bastos es la chispa original: una idea que enciende, un impulso creativo que pide cuerpo de inmediato. Es energía pura buscando dirección; el mejor momento para empezar es ahora, aunque el plan no esté completo.",rev:"Invertido, la chispa no prende: proyectos que se posponen, entusiasmo que se enfría, falta de dirección. La energía existe pero está retenida. Conviene descubrir qué la está apagando antes de forzar el arranque."},{keywords:["planificación","horizonte","decisión"],up:"El Dos de Bastos contempla el mundo desde la muralla con el globo en la mano: el primer logro ya llegó y ahora toca decidir hasta dónde llegar. Habla de planificar la expansión y de elegir entre lo seguro y lo posible.",rev:"Invertido, señala miedo a salir del territorio conocido: planes que se quedan en el papel, ambición frenada por la prudencia. El mundo no vendrá a buscarte a la muralla."},{keywords:["expansión","resultados","previsión"],up:"El Tres de Bastos mira los barcos que ya zarparon: lo sembrado empieza a moverse y el horizonte se ensancha. Anuncia primeros resultados, intercambios en marcha y la confirmación de que la dirección era buena.",rev:"Invertido, advierte de retrasos en lo esperado, falta de previsión o miras demasiado cortas. Los barcos tardan; revisa si el puerto elegido sigue siendo el correcto."},{keywords:["celebración","hogar","estabilidad"],up:"El Cuatro de Bastos levanta un arco de flores: celebración, hogar, una etapa que se consolida y merece fiesta. Habla de estabilidad alegre, reencuentros y logros compartidos.",rev:"Invertido, la celebración se pospone o la base tiembla: tensiones en casa, transiciones incómodas, una alegría que no termina de asentarse. La fiesta llegará, pero antes hay que reparar el arco."},{keywords:["competencia","fricción","reto"],up:"El Cinco de Bastos es el choque de los bastos en alto: competencia, fricción, ideas que pelean por imponerse. No es una batalla grave sino un entrenamiento; del roce puede salir la mejor versión de cada parte.",rev:"Invertido, el conflicto se evita a toda costa o escala más de lo que merece. La tensión no resuelta se vuelve interna. Nombrar el desacuerdo suele costar menos que sostenerlo en silencio."},{keywords:["victoria","reconocimiento","éxito"],up:"El Seis de Bastos entra en la ciudad con la corona de laurel: victoria pública, reconocimiento, el esfuerzo por fin visto. Es permiso para celebrar y para dejarse celebrar.",rev:"Invertido, advierte del pedestal: éxito sin reconocimiento, vanidad que necesita aplauso o miedo a la caída. La victoria que depende del público dura lo que dura el desfile."},{keywords:["defensa","perseverancia","posición"],up:"El Siete de Bastos defiende lo alto de la colina: la posición ganada será disputada y toca sostenerla. Habla de coraje, perseverancia y de la ventaja de quien sabe exactamente qué defiende.",rev:"Invertido, señala sentirse abrumado, ceder terreno por cansancio o defender algo que ya no vale la pena. Antes de seguir resistiendo, pregúntate si la colina sigue siendo tuya."},{keywords:["velocidad","noticias","movimiento"],up:"El Ocho de Bastos cruza el cielo: velocidad, noticias en camino, acontecimientos que se aceleran de golpe. Lo que estaba detenido se mueve; conviene tener las manos libres para recibirlo.",rev:"Invertido, los mensajes se retrasan o llegan demasiados a la vez: prisas mal dirigidas, energía dispersa, frenazos imprevistos. Bajar el ritmo no es perder el impulso."},{keywords:["resistencia","cautela","resiliencia"],up:"El Nueve de Bastos resiste vendado pero en pie: es la última prueba antes del final. Habla de resiliencia, de proteger lo construido y de no soltar justo antes de la meta.",rev:"Invertido, la guardia constante se vuelve agotamiento y desconfianza: ver enemigos donde hay aliados, rendirse a un paso del final. Descansar también es defender la posición."},{keywords:["carga","responsabilidad","esfuerzo"],up:"El Diez de Bastos carga los diez palos a la vez: éxito que pesa, responsabilidad asumida hasta el límite. La meta está cerca, pero conviene revisar qué cargas son realmente tuyas.",rev:"Invertido, anuncia la liberación de un peso o la urgencia de delegarlo: cargar con todo no es mérito sino costumbre. Soltar algunas varas no es abandonar el camino."},{keywords:["entusiasmo","mensaje","exploración"],up:"La Sota de Bastos trae un mensaje encendido: una propuesta, una idea nueva, un entusiasmo joven que quiere ser explorado. Invita a decir sí a lo que despierta curiosidad.",rev:"Invertida, el entusiasmo se dispersa antes de concretarse: proyectos que se anuncian y no empiezan, noticias que tardan. La chispa necesita un mínimo de disciplina para volverse fuego."},{keywords:["aventura","pasión","audacia"],up:"El Caballero de Bastos galopa hacia la aventura: pasión, audacia, energía que no espera permiso. Es excelente para arrancar; conviene que alguien recuerde el mapa.",rev:"Invertido, la pasión se vuelve precipitación: decisiones impulsivas, ira pronta, proyectos abandonados a medio galope. Frenar no es rendirse; es elegir mejor la dirección del salto."},{keywords:["carisma","calidez","confianza"],up:"La Reina de Bastos preside con un girasol en la mano: calidez magnética, confianza, una energía que anima todo lo que toca. Habla de liderar desde el carisma y la generosidad.",rev:"Invertida, la confianza flaquea y aparecen los celos o la exigencia: querer brillar apagando otras luces. Su fuego no necesita competir; necesita volver a su propio centro."},{keywords:["liderazgo","visión","emprendimiento"],up:"El Rey de Bastos gobierna el fuego con visión: es el emprendedor maduro, el líder que convierte la inspiración en estrategia. Anuncia decisiones audaces tomadas con experiencia.",rev:"Invertido, el visionario se vuelve autoritario: expectativas imposibles, impaciencia con los ritmos ajenos, liderazgo que no escucha. La visión sin equipo es solo un monólogo."}]},{suit:"copas",label:"Copas",meanings:[{keywords:["amor","intuición","apertura"],up:"El As de Copas desborda agua viva: un comienzo emocional, amor que se ofrece, intuición y creatividad que fluyen sin esfuerzo. Es una invitación a recibir con el corazón abierto.",rev:"Invertido, la copa está tapada o vacía: emociones contenidas, amor que no encuentra cauce, desconexión de lo que se siente. Antes de llenar la copa hay que destaparla."},{keywords:["unión","reciprocidad","alianza"],up:"El Dos de Copas brinda en reciprocidad: una unión equilibrada, romántica o no, donde ambas partes dan y reciben. Anuncia alianzas sinceras y reconciliaciones.",rev:"Invertido, el brindis se desequilibra: malentendidos, una parte que da más de lo que recibe, vínculos que piden conversación. La balanza emocional también se calibra hablando."},{keywords:["amistad","celebración","comunidad"],up:"El Tres de Copas alza las copas entre amigas: celebración compartida, comunidad, la alegría que se multiplica al dividirse. Habla de apoyos que sostienen y de festejar los logros ajenos como propios.",rev:"Invertido, advierte de excesos en la fiesta, de grupos que asfixian o de terceras personas en discordia. La comunidad nutre cuando deja espacio para cada voz."},{keywords:["apatía","introspección","oportunidad"],up:"El Cuatro de Copas medita bajo el árbol sin ver la copa que se le ofrece: apatía, desencanto, atención puesta en lo que falta. Hay una oportunidad delante; solo pide levantar la mirada.",rev:"Invertido, anuncia el final del ensimismamiento: nuevas motivaciones, ganas de aceptar lo que la vida ofrece. La copa sigue ahí, y esta vez se ve."},{keywords:["pérdida","duelo","aceptación"],up:"El Cinco de Copas llora las tres copas derramadas de espaldas a las dos que siguen en pie: duelo, pérdida, la mirada fija en lo que se fue. El dolor es legítimo; las copas intactas, también.",rev:"Invertido, comienza la aceptación: perdonar, perdonarse, girar el cuerpo hacia lo que queda. El duelo no se salta, pero sí termina."},{keywords:["nostalgia","recuerdos","inocencia"],up:"El Seis de Copas regala flores en un patio de infancia: nostalgia dulce, recuerdos, gestos inocentes que reconfortan. Puede anunciar reencuentros o regalos que llegan del pasado.",rev:"Invertido, la nostalgia se vuelve residencia: vivir hacia atrás, idealizar lo que fue, resistirse a crecer. El pasado es buen visitante y mal casero."},{keywords:["opciones","fantasía","elección"],up:"El Siete de Copas sueña ante siete copas llenas de espejismos: opciones, fantasías, deseos que se confunden entre sí. Imaginar es fértil; elegir es lo que vuelve real una de las copas.",rev:"Invertido, la niebla se despeja: fin del autoengaño, claridad para elegir, pies que vuelven al suelo. Menos opciones imaginadas, más camino andado."},{keywords:["partida","búsqueda","desapego"],up:"El Ocho de Copas se aleja de las copas apiladas bajo la luna: dejar atrás algo que funcionaba pero ya no llena. Es la búsqueda de un sentido más hondo, aunque cueste partir.",rev:"Invertido, señala el miedo a partir o el regreso a lo dejado: quedarse por costumbre, dudar del propio anhelo. Ni huir ni quedarse a medias: la pregunta es qué llena de verdad."},{keywords:["satisfacción","deseo","disfrute"],up:"El Nueve de Copas sonríe con sus copas en exposición: deseo cumplido, satisfacción, el famoso sí del tarot a lo que se pregunta. Es permiso para disfrutar de lo logrado.",rev:"Invertido, el deseo cumplido sabe a poco: complacencia, placeres que no llenan, vanidad de coleccionista. Quizá el deseo apuntaba a otra cosa; vale la pena reformularlo."},{keywords:["plenitud","familia","armonía"],up:"El Diez de Copas dibuja un arcoíris sobre la familia: plenitud emocional, armonía en casa, vínculos que sostienen. Es la copa compartida, no la individual: la alegría hecha hogar.",rev:"Invertido, advierte del hogar idealizado: expectativas de postal, conflictos tapados por la foto familiar. La armonía real admite días nublados."},{keywords:["sensibilidad","mensaje","imaginación"],up:"La Sota de Copas trae un pez asomado a la copa: un mensaje del corazón, una invitación creativa, sensibilidad que sorprende. Habla de dejarse sorprender por lo que se siente.",rev:"Invertida, la sensibilidad se desborda o se esconde: inmadurez afectiva, escapismo soñador, mensajes emocionales que no se entregan. Sentir mucho no exime de decirlo claro."},{keywords:["romanticismo","propuesta","encanto"],up:"El Caballero de Copas avanza despacio con la copa en alto: es el romántico del tarot, la propuesta, el gesto bello hecho con intención. Anuncia invitaciones y declaraciones.",rev:"Invertido, el encanto pierde sustancia: promesas que no se cumplen, idealización, desencanto al conocer al mensajero. La belleza del gesto se mide en su cumplimiento."},{keywords:["empatía","intuición","cuidado"],up:"La Reina de Copas sostiene su copa cerrada y escucha: empatía profunda, intuición madura, cuidado que no invade. Es el corazón que contiene sin ahogarse en lo que contiene.",rev:"Invertida, la empatía se desborda: cargar con emociones ajenas, dependencia afectiva, sensibilidad sin orillas. Cuidarse no es egoísmo; es lo que hace posible cuidar."},{keywords:["madurez emocional","serenidad","consejo"],up:"El Rey de Copas navega aguas agitadas sin derramar su copa: madurez emocional, calma en la tormenta, consejo sabio. Sentir hondo y actuar sereno no son contrarios.",rev:"Invertido, la calma es fachada: frialdad, humor cambiante o manipulación afectiva. Las aguas que no se nombran terminan moviendo el barco igual."}]},{suit:"espadas",label:"Espadas",meanings:[{keywords:["claridad","verdad","decisión"],up:"El As de Espadas corta el aire con una verdad: claridad mental repentina, una idea decisiva, justicia que se abre paso. Es excelente para decidir, firmar o nombrar lo que estaba confuso.",rev:"Invertido, la mente se nubla: ideas confusas, decisiones forzadas, verdades usadas como arma. Una espada sin puntería hace daño hasta en la vaina."},{keywords:["indecisión","tregua","dilema"],up:"El Dos de Espadas cruza las armas con los ojos vendados: una tregua, una decisión aplazada, equilibrio sostenido a base de no mirar. La calma es real, pero provisional.",rev:"Invertido, la venda cae: llega información, y la decisión ya no admite espera. El desempate puede ser incómodo, pero la parálisis cobraba intereses."},{keywords:["dolor","ruptura","verdad"],up:"El Tres de Espadas atraviesa el corazón bajo la lluvia: dolor, ruptura, una verdad que duele precisamente porque es verdad. Nombrar la herida es el primer punto de sutura.",rev:"Invertido, la herida empieza a cerrar: perdón, alivio lento, o bien un dolor que se alarga por no ser atendido. La lluvia termina; conviene no quedarse a vivir en ella."},{keywords:["descanso","recuperación","pausa"],up:"El Cuatro de Espadas descansa en la capilla: pausa necesaria, recuperación, silencio que repara la mente. No es rendición: es el mantenimiento del guerrero.",rev:"Invertido, advierte del descanso negado o forzoso: agotamiento que se ignora hasta que obliga a parar, o un retiro que ya duró demasiado. Ni huelga de sueño ni hibernación."},{keywords:["conflicto","derrota","orgullo"],up:"El Cinco de Espadas recoge las armas de los vencidos: una victoria con coste, un conflicto donde todos pierden algo. Pregunta si ganar esta discusión vale el campo que deja detrás.",rev:"Invertido, abre la puerta a la reconciliación: soltar el orgullo, reparar lo dicho, retirarse de batallas que no construyen. Perder una pelea puede ser ganar la paz."},{keywords:["transición","viaje","alivio"],up:"El Seis de Espadas cruza el agua hacia la otra orilla: transición, alejarse de la turbulencia, viaje hacia aguas más calmas. El equipaje pesa, pero la dirección es buena.",rev:"Invertido, la travesía se complica: resistencia a partir, asuntos pendientes que tiran de la barca, regresos a la orilla vieja. Algunas despedidas hay que terminar de hacerlas."},{keywords:["estrategia","sigilo","astucia"],up:"El Siete de Espadas se lleva las armas de puntillas: estrategia, sigilo, ingenio para evitar el enfrentamiento directo. A veces es astucia legítima; otras, un engaño que pide revisión.",rev:"Invertido, el plan queda al descubierto: confesiones, secretos que salen a la luz, astucia que se vuelve contra su autor. La verdad tiene mejor logística que la mentira."},{keywords:["restricción","creencias","liberación"],up:"El Ocho de Espadas está atado entre espadas que no lo tocan: restricción mental, creencias que aprisionan más que los hechos. La salida existe; el primer nudo está en la mirada.",rev:"Invertido, los nudos ceden: perspectivas nuevas, fin del victimismo, libertad recuperada paso a paso. Nadie vuelve a atarse igual después de verse las manos libres."},{keywords:["ansiedad","insomnio","preocupación"],up:"El Nueve de Espadas despierta a medianoche con la cara entre las manos: ansiedad, insomnio, preocupaciones que crecen en la oscuridad. El miedo nocturno es mal cartógrafo: distorsiona el tamaño de todo.",rev:"Invertido, la noche empieza a ceder: las preocupaciones pierden volumen a la luz del día y pedir ayuda se vuelve posible. Hablado, el monstruo suele medir la mitad."},{keywords:["final","traición","renacer"],up:"El Diez de Espadas yace con las diez espadas a la espalda: un final doloroso, una traición, el fondo del pozo. Su único consuelo es literal: desde aquí, todo camino es ascenso.",rev:"Invertido, anuncia la recuperación lenta o el desastre evitado por poco: las heridas cierran y el amanecer del fondo de la carta gana terreno. Levantarse también es un proceso."},{keywords:["curiosidad","vigilancia","agilidad mental"],up:"La Sota de Espadas vigila con la espada en alto: curiosidad intelectual, mente despierta, alguien que observa y aprende rápido. Buen momento para preguntar, investigar y verificar.",rev:"Invertida, la mente despierta se vuelve inquieta de más: chismes, conclusiones precipitadas, palabras que cortan sin querer. Afilar la lengua no es lo mismo que afinar el juicio."},{keywords:["determinación","velocidad","ofensiva"],up:"El Caballero de Espadas carga a todo galope contra el viento: determinación intelectual, defensa apasionada de una idea, acción directa. Imparable, para bien y para mal.",rev:"Invertido, la carga pierde el control: agresividad verbal, imprudencia, choques que se podían rodear. La velocidad sin dirección solo garantiza llegar antes al lugar equivocado."},{keywords:["percepción","independencia","juicio"],up:"La Reina de Espadas señala con la mano y sostiene la espada recta: percepción aguda, independencia, juicio limpio de sentimentalismos. Dice las verdades con precisión de cirujana.",rev:"Invertida, la precisión se vuelve frialdad: crítica que hiere, amargura acumulada, distancia usada como armadura. La claridad no necesita crueldad para ser clara."},{keywords:["autoridad","ética","razón"],up:"El Rey de Espadas preside con la espada apenas inclinada: autoridad intelectual, ética, el consejo de quien domina su materia. Anuncia decisiones justas tomadas con la cabeza fría.",rev:"Invertido, el intelecto se vuelve instrumento de poder: manipulación, rigidez, juicios sin apelación. La espada de la mente también jura un código."}]},{suit:"oros",label:"Oros",meanings:[{keywords:["oportunidad","prosperidad","semilla"],up:"El As de Oros ofrece una moneda desde la nube: una oportunidad material concreta, semilla de prosperidad, un comienzo con los pies en la tierra. Lo que se plante ahora tiene vocación de durar.",rev:"Invertido, la oportunidad se escapa o llega torcida: malas inversiones, planes sin base, prosperidad que se queda en promesa. Revisa el terreno antes de volver a sembrar."},{keywords:["equilibrio","adaptación","prioridades"],up:"El Dos de Oros hace malabares con dos monedas unidas por un lazo infinito: equilibrio en movimiento, adaptabilidad, varias prioridades danzando a la vez. El secreto no es parar: es el ritmo.",rev:"Invertido, los malabares se caen: sobrecarga, desorden financiero, compromisos que ya no caben en las manos. Soltar una bola a tiempo es mejor que perderlas todas."},{keywords:["colaboración","maestría","reconocimiento"],up:"El Tres de Oros reúne al artesano con quienes valoran su obra: trabajo en equipo, maestría reconocida, colaboración donde cada parte aporta lo suyo. La calidad se nota y se nombra.",rev:"Invertido, la obra se resiente: descoordinación, esfuerzo sin reconocimiento, trabajo hecho a desgana. El talento aislado rinde menos que el oficio compartido."},{keywords:["ahorro","control","seguridad"],up:"El Cuatro de Oros abraza su moneda con todo el cuerpo: ahorro, control, conservar lo ganado. La seguridad es legítima; el agarrotamiento, no tanto.",rev:"Invertido, la mano se abre: gastos liberados, generosidad recuperada o, en exceso, control que se pierde. Ni caja fuerte ni manirroto: la moneda existe para circular con criterio."},{keywords:["carencia","exclusión","ayuda"],up:"El Cinco de Oros camina en la nieve frente a la ventana iluminada: carencia, exclusión, la sensación de quedarse fuera. La ayuda está más cerca de lo que la nieve deja ver.",rev:"Invertido, la racha adversa amaina: ayuda que llega, recuperación material o anímica, puertas que vuelven a abrirse. El frío enseñó dónde están los abrigos."},{keywords:["generosidad","equilibrio","deuda"],up:"El Seis de Oros pesa las monedas antes de darlas: generosidad con balanza, dar y recibir en justa medida, deudas que se saldan. Hoy puede tocarte cualquiera de los dos lados.",rev:"Invertido, la balanza se inclina: generosidad con condiciones, deudas que pesan, ayuda que humilla en vez de levantar. Dar bien es un arte; recibir bien, otro."},{keywords:["paciencia","evaluación","cosecha"],up:"El Siete de Oros se apoya en la azada y contempla la mata crecida: paciencia, evaluación, la pausa del agricultor antes de la cosecha. Lo invertido está creciendo; no lo desentierres para comprobarlo.",rev:"Invertido, la espera impacienta: esfuerzo mal dirigido, ganas de abandonar antes del fruto. Quizá toca ajustar el cultivo, no quemarlo."},{keywords:["oficio","dedicación","aprendizaje"],up:"El Ocho de Oros talla moneda tras moneda en su banco de trabajo: oficio, dedicación, el aprendizaje que se vuelve maestría a base de repetición consciente. El trabajo bien hecho es su propia recompensa, y además paga.",rev:"Invertido, el cincel pierde sentido: trabajo sin alma, perfeccionismo paralizante o chapuza por desgana. El oficio se recupera volviendo a amar el detalle, no sumando horas."},{keywords:["independencia","abundancia","disfrute"],up:"El Nueve de Oros pasea por su viñedo con el halcón en la mano: independencia, abundancia ganada, el disfrute sereno de lo construido. Es el lujo de no deberle el bienestar a nadie.",rev:"Invertido, advierte del jardín dorado con cerradura: dependencia material, gastos para aparentar, soledad entre las vides. La abundancia que aísla es solo decorado."},{keywords:["legado","familia","estabilidad"],up:"El Diez de Oros reúne a tres generaciones bajo el arco del escudo: legado, estabilidad duradera, riqueza que trasciende a una sola vida. Habla de raíces, herencias y de construir para quienes vienen.",rev:"Invertido, el legado se disputa: conflictos familiares por lo material, estabilidad solo aparente, tradiciones que pesan. La verdadera herencia no siempre se guarda en el banco."},{keywords:["estudio","aplicación","noticias"],up:"La Sota de Oros contempla su moneda como quien estudia: aplicación, ganas de aprender un oficio, noticias de dinero o de estudios. Anuncia comienzos modestos con vocación de fruto.",rev:"Invertida, el estudio se dispersa: distracciones, resultados que tardan, planes materiales sin primer paso. La moneda no crece mirándola: se invierte en horas concretas."},{keywords:["constancia","método","fiabilidad"],up:"El Caballero de Oros avanza al paso, sin prisa y sin pausa: constancia, método, fiabilidad absoluta. No es el más veloz del tarot, pero es el único que siempre llega.",rev:"Invertido, el paso firme se vuelve rutina paralizante: aburrimiento, lentitud excesiva, resistencia a todo cambio. La constancia sirve a un destino, no al surco mismo."},{keywords:["abundancia práctica","cuidado","hogar"],up:"La Reina de Oros cuida su moneda en un trono entre flores: abundancia práctica, cuidado tangible, la inteligencia de hacer hogar en cualquier parte. Nutre sin descuidarse.",rev:"Invertida, el cuidado se desequilibra: todo para el trabajo o todo para los demás, y el autocuidado en último lugar. El jardín de la Reina también la incluye a ella."},{keywords:["prosperidad","solidez","generosidad"],up:"El Rey de Oros reposa la mano sobre el toro de su trono: prosperidad consolidada, éxito sólido, la generosidad de quien ya no tiene nada que demostrar. Es el mecenas del tarot.",rev:"Invertido, la solidez se endurece: materialismo, terquedad, medirlo todo en cifras. La riqueza que no se disfruta ni se comparte es solo inventario."}]}].flatMap((a,b)=>a.meanings.map((c,d)=>{let f=e[d];return{id:22+14*b+d,slug:`${f.rankSlug}-de-${a.suit}`,name:`${f.rank} de ${a.label}`,number:f.number,roman:f.roman,arcana:"menor",suit:a.suit,keywords:c.keywords,meaningUpright:c.up,meaningReversed:c.rev}})),g="dorado-mistico",h={bastos:"Bastos",copas:"Copas",espadas:"Espadas",oros:"Oros"};function i(a){return a.suit?`${a.roman} \xb7 ${h[a.suit]}`:a.roman}function j(a){return a.suit??"arcanos-mayores"}function k(a,b,c=g){let d=c===g?"/cards":`/cards/${c}`;return`${d}/${a}/${b}.jpg`}function l({slug:a,name:e,roman:f,category:g="arcanos-mayores",deck:h,large:i=!1}){let[j,l]=(0,c.useState)(!1);return(0,b.jsx)("div",{className:`card-frame ${i?"is-large":""}`,children:j?(0,b.jsxs)("div",{className:"card-placeholder","aria-label":`Carta del tarot: ${e}`,children:[(0,b.jsx)("span",{className:"ph-roman",children:f}),(0,b.jsx)(d.MoonStars,{className:"ph-ornament",size:i?28:18,weight:"thin"}),(0,b.jsx)("span",{className:"ph-name",children:e})]}):(0,b.jsx)("img",{src:k(g,a,h),alt:`Carta del tarot: ${e}`,loading:i?"eager":"lazy",onError:()=>l(!0)})})}[...[{slug:"el-loco",name:"El Loco",number:0,roman:"0",keywords:["comienzos","libertad","espontaneidad"],meaningUpright:"El Loco anuncia un comienzo absoluto: un camino que se abre sin mapa y sin garantías. Invita a confiar en el impulso vital, a viajar ligero de equipaje y a dar el salto aunque el borde del precipicio esté cerca. Es la energía de quien todavía no sabe, y precisamente por eso puede aprenderlo todo.",meaningReversed:"Invertido, El Loco advierte de la imprudencia o de su opuesto exacto: la parálisis ante el cambio. Puede señalar decisiones tomadas sin medir consecuencias, o un miedo que disfraza de prudencia las ganas de no moverse. Conviene revisar si el salto es huida o si la espera es excusa."},{slug:"el-mago",name:"El Mago",number:1,roman:"I",keywords:["voluntad","recursos","manifestación"],meaningUpright:"El Mago reúne sobre su mesa todos los elementos: tiene las herramientas, el talento y el momento. Habla de concentrar la voluntad para convertir una idea en algo tangible. Lo que se necesita ya está disponible; falta únicamente decidirse a usarlo.",meaningReversed:"Invertido, El Mago señala talento disperso, promesas infladas o manipulación. La energía existe pero se fuga en mil direcciones, o se emplea para aparentar más que para construir. Es momento de revisar intenciones y volver a un solo objetivo claro."},{slug:"la-sacerdotisa",name:"La Sacerdotisa",number:2,roman:"II",keywords:["intuición","misterio","saber interior"],meaningUpright:"La Sacerdotisa custodia lo que aún no debe decirse en voz alta. Pide silencio, escucha interna y confianza en la intuición antes que en la lógica visible. Hay información que llegará sola si se deja de forzar la respuesta.",meaningReversed:"Invertida, sugiere desconexión de la propia voz interior: se buscan afuera respuestas que ya se conocen por dentro. También puede señalar secretos que pesan o verdades calladas demasiado tiempo. Recuperar la quietud es el primer paso."},{slug:"la-emperatriz",name:"La Emperatriz",number:3,roman:"III",keywords:["abundancia","creatividad","cuidado"],meaningUpright:"La Emperatriz es tierra fértil: todo lo que se siembra cerca de ella crece. Habla de creatividad en expansión, de cuidar y ser cuidado, de proyectos que maduran a su propio ritmo. Es una invitación a nutrir lo que importa con paciencia y generosidad.",meaningReversed:"Invertida, puede indicar un bloqueo creativo, descuido de uno mismo o un cuidado que asfixia en lugar de nutrir. La abundancia se percibe lejana porque la energía está puesta en sostener a otros sin reponer la propia."},{slug:"el-emperador",name:"El Emperador",number:4,roman:"IV",keywords:["estructura","autoridad","estabilidad"],meaningUpright:"El Emperador ordena el territorio: establece límites, reglas y cimientos sobre los que construir a largo plazo. Representa la autoridad serena, la disciplina que protege y la estabilidad ganada con método. Es buen momento para estructurar lo que estaba suelto.",meaningReversed:"Invertido, la estructura se vuelve jaula: rigidez, control excesivo o abuso de autoridad, propio o ajeno. También puede señalar falta total de orden, un reino sin gobierno. El equilibrio está entre la norma y la vida que la habita."},{slug:"el-hierofante",name:"El Hierofante",number:5,roman:"V",keywords:["tradición","enseñanza","guía"],meaningUpright:"El Hierofante transmite un saber heredado: maestros, instituciones, linajes y caminos probados por otros. Sugiere buscar consejo en quien ya recorrió la ruta, o formalizar un aprendizaje. La tradición, bien entendida, es un atajo y no una cadena.",meaningReversed:"Invertido, cuestiona el dogma: las reglas recibidas ya no responden a las preguntas actuales. Puede anunciar una ruptura necesaria con estructuras, creencias o mentores. Conviene distinguir entre rebeldía fértil y simple rechazo por sistema."},{slug:"los-enamorados",name:"Los Enamorados",number:6,roman:"VI",keywords:["elección","unión","armonía"],meaningUpright:"Los Enamorados hablan de una unión que transforma, pero sobre todo de una elección consciente. Hay un cruce de caminos donde el corazón y los valores deben ir juntos. Elegir bien aquí significa elegir con todo el ser, no solo con el deseo.",meaningReversed:"Invertida, señala desalineación: lo que se hace no coincide con lo que se siente, o una relación pierde su armonía por falta de decisión. Posponer la elección es también elegir. Es tiempo de honestidad con uno mismo."},{slug:"el-carro",name:"El Carro",number:7,roman:"VII",keywords:["determinación","victoria","rumbo"],meaningUpright:"El Carro avanza porque su conductor domina fuerzas opuestas sin anularlas. Es la victoria que se obtiene con voluntad firme y dirección clara. Si el objetivo está definido, este es el momento de acelerar.",meaningReversed:"Invertido, el impulso existe pero falta el rumbo: movimiento sin dirección, prisa que atropella o un proyecto que se descontrola. Antes de seguir empujando conviene preguntarse hacia dónde, exactamente, se quiere llegar."},{slug:"la-fuerza",name:"La Fuerza",number:8,roman:"VIII",keywords:["coraje","compasión","dominio interior"],meaningUpright:"La Fuerza no doma al león con violencia sino con serenidad. Representa el coraje suave, la paciencia que vence donde la imposición fracasa, y el dominio de los propios impulsos. La verdadera firmeza aquí es interior.",meaningReversed:"Invertida, revela inseguridad disfrazada de dureza, o impulsos que toman el mando. La energía se gasta en pelear contra uno mismo. Recuperar la calma no es rendirse: es la condición para volver a ser fuerte."},{slug:"el-ermitano",name:"El Ermitaño",number:9,roman:"IX",keywords:["introspección","búsqueda","sabiduría"],meaningUpright:"El Ermitaño se retira para ver mejor. Su lámpara ilumina solo el siguiente paso, y con eso basta. Anuncia un periodo de introspección fértil, de búsqueda de sentido lejos del ruido. Lo que se encuentre en ese silencio valdrá el camino.",meaningReversed:"Invertido, el retiro se convierte en aislamiento: soledad no elegida, desconexión del mundo o negativa a recibir ayuda. La lámpara sigue encendida, pero nadie puede verla si la puerta permanece cerrada demasiado tiempo."},{slug:"la-rueda-de-la-fortuna",name:"La Rueda de la Fortuna",number:10,roman:"X",keywords:["ciclos","destino","oportunidad"],meaningUpright:"La Rueda gira y nada permanece en el mismo punto. Anuncia un giro del destino, el cierre de un ciclo y la apertura de otro. Lo inteligente no es frenar la rueda sino aprender a moverse con ella: hay una oportunidad en el cambio que se acerca.",meaningReversed:"Invertida, señala resistencia al movimiento natural de las cosas, o una racha adversa que pide paciencia más que acción. Los ciclos bajos también terminan. Conviene soltar el control sobre lo que nunca estuvo en nuestras manos."},{slug:"la-justicia",name:"La Justicia",number:11,roman:"XI",keywords:["equidad","verdad","consecuencia"],meaningUpright:"La Justicia pesa con exactitud: cada acto tiene su consecuencia y cada verdad su lugar. Habla de decisiones tomadas con claridad, de acuerdos justos y de asumir la responsabilidad propia. La balanza se equilibra cuando se actúa con rectitud.",meaningReversed:"Invertida, advierte de un desequilibrio: una injusticia recibida o cometida, verdades a medias, cuentas que no cuadran. Antes de señalar afuera, conviene revisar la propia parte. La balanza siempre termina por ajustarse."},{slug:"el-colgado",name:"El Colgado",number:12,roman:"XII",keywords:["pausa","perspectiva","entrega"],meaningUpright:"El Colgado está suspendido por voluntad propia: su quietud es una forma de sabiduría. Invita a pausar, a mirar el problema desde el ángulo opuesto y a soltar la urgencia de resolver. Lo que parece detenido está, en realidad, madurando.",meaningReversed:"Invertido, la pausa se vuelve estancamiento: se sacrifica tiempo y energía sin que nada cambie. Puede señalar una espera que ya no tiene sentido o un sacrificio que nadie pidió. Es hora de bajarse del árbol y caminar."},{slug:"la-muerte",name:"La Muerte",number:13,roman:"XIII",keywords:["transformación","cierre","renovación"],meaningUpright:"La Muerte rara vez habla de muerte: habla de finales necesarios. Algo termina para que algo más pueda existir. Es la carta de la transformación profunda, la poda que permite el brote. Cerrar bien es la forma más honesta de empezar.",meaningReversed:"Invertida, señala un final que se resiste: aferrarse a lo que ya cumplió su ciclo, alargar despedidas, sostener estructuras vacías. La transición está bloqueada no por el destino sino por el miedo a soltar."},{slug:"la-templanza",name:"La Templanza",number:14,roman:"XIV",keywords:["equilibrio","moderación","alquimia"],meaningUpright:"La Templanza mezcla las aguas con un pulso imposible: ni una gota se derrama. Habla de encontrar la medida justa, de integrar opuestos y de avanzar con paciencia de artesano. La armonía aquí no es ausencia de tensión sino su manejo exacto.",meaningReversed:"Invertida, advierte de excesos o de oscilaciones bruscas: todo o nada, prisa o abandono. La mezcla se corta porque falta paciencia. Recuperar el ritmo propio, aunque sea más lento, devuelve la estabilidad."},{slug:"el-diablo",name:"El Diablo",number:15,roman:"XV",keywords:["apego","deseo","sombra"],meaningUpright:"El Diablo muestra las cadenas que nosotros mismos elegimos: apegos, hábitos, deseos que gobiernan en silencio. No es una condena sino un espejo. Reconocer la propia sombra es el primer acto de libertad; las cadenas de esta carta están sueltas.",meaningReversed:"Invertido, anuncia liberación: una toma de conciencia que afloja el nudo, el principio del desapego. Lo que dominaba pierde fuerza. Es buen momento para romper un patrón que ya fue visto y nombrado."},{slug:"la-torre",name:"La Torre",number:16,roman:"XVI",keywords:["ruptura","revelación","verdad súbita"],meaningUpright:"La Torre cae porque estaba construida sobre una base falsa. Es la ruptura súbita que nadie pide y casi todos necesitan: una verdad que derriba estructuras para dejar el terreno limpio. Duele, pero lo que sobrevive a La Torre es real.",meaningReversed:"Invertida, puede señalar una catástrofe evitada por poco, o un derrumbe que se pospone apuntalando lo que ya no se sostiene. El miedo al colapso retrasa lo inevitable. A veces es mejor desmontar con las propias manos."},{slug:"la-estrella",name:"La Estrella",number:17,roman:"XVII",keywords:["esperanza","inspiración","sanación"],meaningUpright:"Después de la tormenta, La Estrella: agua limpia, cielo abierto, una guía serena en la oscuridad. Anuncia un tiempo de sanación y de fe renovada. No promete la llegada inmediata, pero sí que la dirección es correcta.",meaningReversed:"Invertida, habla de una esperanza apagada: cansancio de creer, inspiración que no llega, fe puesta en el lugar equivocado. La estrella sigue ahí; es la mirada la que está baja. Levantar la vista es el trabajo de esta etapa."},{slug:"la-luna",name:"La Luna",number:18,roman:"XVIII",keywords:["intuición","ilusión","inconsciente"],meaningUpright:"La Luna ilumina un paisaje incierto donde nada es exactamente lo que parece. Habla del territorio del sueño, la intuición y los miedos antiguos. No es momento de decidir con datos, porque los datos engañan: es momento de escuchar lo que se sabe sin saber cómo.",meaningReversed:"Invertida, la niebla comienza a disiparse: una confusión se aclara, un engaño sale a la luz, un miedo pierde tamaño al ser mirado de frente. La noche termina. Conviene anotar lo aprendido antes de que el día lo borre."},{slug:"el-sol",name:"El Sol",number:19,roman:"XIX",keywords:["éxito","vitalidad","claridad"],meaningUpright:"El Sol no admite dobles lecturas: es la carta de la alegría plena, la claridad y el éxito que se puede celebrar a plena luz. Lo que estaba confuso se vuelve evidente, lo que estaba frío recupera calor. Disfrutar también es parte del camino.",meaningReversed:"Invertido, el brillo se nubla apenas: un optimismo algo forzado, un logro que no se deja disfrutar, vitalidad en pausa. La luz no se ha ido, está detrás de una nube pasajera. Pedir menos perfección suele despejar el cielo."},{slug:"el-juicio",name:"El Juicio",number:20,roman:"XX",keywords:["despertar","balance","llamada"],meaningUpright:"El Juicio suena como una llamada imposible de ignorar: es hora de hacer balance, perdonar lo que pese y responder a una vocación que insiste. Algo dormido despierta. Las decisiones tomadas ahora tienen el peso de un nuevo comienzo.",meaningReversed:"Invertido, la llamada se escucha pero no se responde: autocrítica que paraliza, miedo al veredicto propio, balances que se postergan. El pasado solo pesa mientras no se revisa. Nadie más puede responder esta llamada."},{slug:"el-mundo",name:"El Mundo",number:21,roman:"XXI",keywords:["culminación","plenitud","integración"],meaningUpright:"El Mundo cierra el viaje de los arcanos: es la culminación, el círculo completo, la danza de quien integró todas sus etapas. Anuncia un logro redondo y la sensación de estar, por fin, en el lugar correcto. Todo final así es también una puerta.",meaningReversed:"Invertido, señala un cierre pendiente: la meta está cerca pero algo queda sin resolver, un último paso que se evita. La vuelta no estará completa hasta atender ese detalle. Terminar bien importa tanto como empezar."}].map((a,b)=>({...a,id:b,arcana:"mayor",suit:null})),...f]}];

